import{_ as a,c as e,o as r,a1 as o}from"./chunks/framework.DILC4Csi.js";const f=JSON.parse('{"title":"고급 기능","description":"Clawdbot의 고급 기능 구성을 학습합니다. AI 모델 구성, 다중 Agent 협업, 브라우저 자동화, 명령 실행 도구, 웹 검색 도구, Canvas 시각화 인터페이스, 음성 웨이크업 및 TTS, 메모리 시스템, Cron 예약 작업, 스킬 플랫폼, 보안 샌드박스 및 원격 Gateway를 포함합니다.","frontmatter":{"title":"고급 기능","sidebarTitle":"AI 초능력 잠금 해제","subtitle":"고급 기능","description":"Clawdbot의 고급 기능 구성을 학습합니다. AI 모델 구성, 다중 Agent 협업, 브라우저 자동화, 명령 실행 도구, 웹 검색 도구, Canvas 시각화 인터페이스, 음성 웨이크업 및 TTS, 메모리 시스템, Cron 예약 작업, 스킬 플랫폼, 보안 샌드박스 및 원격 Gateway를 포함합니다.","prerequisite":["start/getting-started","start/gateway-startup"],"order":185},"headers":[],"relativePath":"ko/moltbot/moltbot/advanced/index.md","filePath":"ko/moltbot/moltbot/advanced/index.md"}'),d={name:"ko/moltbot/moltbot/advanced/index.md"};function l(h,t,i,n,s,b){return r(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="고급-기능" tabindex="-1">고급 기능 <a class="header-anchor" href="#고급-기능" aria-label="Permalink to &quot;고급 기능&quot;">​</a></h1><h2 id="개요" tabindex="-1">개요 <a class="header-anchor" href="#개요" aria-label="Permalink to &quot;개요&quot;">​</a></h2><p>이 장에서는 Clawdbot의 고급 기능을 심층적으로 소개하며, AI 어시스턴트의 강력한 기능을 최대한 활용할 수 있도록 도와드립니다. AI 모델 구성 및 다중 Agent 협업부터 브라우저 자동화, 메모리 시스템 및 음성 기능까지, 필요에 따라 학습 내용을 선택할 수 있습니다.</p><div class="info custom-block"><p class="custom-block-title">사전 요구사항</p><p>이 장을 학습하기 전에 다음 내용을 완료하세요:</p><ul><li><a href="./../../start/getting-started/">빠른 시작</a></li><li><a href="./../../start/gateway-startup/">Gateway 시작</a></li></ul></div><h2 id="학습-경로" tabindex="-1">학습 경로 <a class="header-anchor" href="#학습-경로" aria-label="Permalink to &quot;학습 경로&quot;">​</a></h2><p>요구사항에 따라 다른 학습 경로를 선택할 수 있습니다:</p><h3 id="🚀-빠른-시작-경로-신규-사용자-추천" tabindex="-1">🚀 빠른 시작 경로 (신규 사용자 추천) <a class="header-anchor" href="#🚀-빠른-시작-경로-신규-사용자-추천" aria-label="Permalink to &quot;🚀 빠른 시작 경로 (신규 사용자 추천)&quot;">​</a></h3><ol><li><a href="./models-auth/">AI 모델 및 인증 구성</a> - 선호하는 AI 모델 구성</li><li><a href="./tools-exec/">명령 실행 도구 및 승인</a> - AI가 명령을 안전하게 실행하도록 설정</li><li><a href="./tools-web/">웹 검색 및 스크래핑 도구</a> - AI의 지식 습득 능력 확장</li></ol><h3 id="🤖-ai-능력-확장-경로" tabindex="-1">🤖 AI 능력 확장 경로 <a class="header-anchor" href="#🤖-ai-능력-확장-경로" aria-label="Permalink to &quot;🤖 AI 능력 확장 경로&quot;">​</a></h3><ol><li><a href="./session-management/">세션 관리 및 다중 Agent</a> - AI 협업 메커니즘 이해</li><li><a href="./memory-system/">메모리 시스템 및 벡터 검색</a> - AI가 중요한 정보를 기억하도록 설정</li><li><a href="./skills-platform/">스킬 플랫폼 및 ClawdHub</a> - 스킬 팩 사용 및 공유</li></ol><h3 id="🔧-자동화-도구-경로" tabindex="-1">🔧 자동화 도구 경로 <a class="header-anchor" href="#🔧-자동화-도구-경로" aria-label="Permalink to &quot;🔧 자동화 도구 경로&quot;">​</a></h3><ol><li><a href="./tools-browser/">브라우저 자동화 도구</a> - 웹페이지 작업 자동화</li><li><a href="./cron-automation/">Cron 예약 작업 및 Webhook</a> - 예약 작업 및 이벤트 트리거</li><li><a href="./remote-gateway/">원격 Gateway 및 Tailscale</a> - 원격 AI 어시스턴트 액세스</li></ol><h3 id="🎨-상호작용-경험-경로" tabindex="-1">🎨 상호작용 경험 경로 <a class="header-anchor" href="#🎨-상호작용-경험-경로" aria-label="Permalink to &quot;🎨 상호작용 경험 경로&quot;">​</a></h3><ol><li><a href="./canvas/">Canvas 시각화 인터페이스 및 A2UI</a> - 시각화 상호작용 인터페이스</li><li><a href="./voice-tts/">음성 웨이크업 및 텍스트 음성 변환</a> - 음성 상호작용 기능</li></ol><h3 id="🔒-보안-및-배포-경로" tabindex="-1">🔒 보안 및 배포 경로 <a class="header-anchor" href="#🔒-보안-및-배포-경로" aria-label="Permalink to &quot;🔒 보안 및 배포 경로&quot;">​</a></h3><ol><li><a href="./security-sandbox/">보안 및 샌드박스 격리</a> - 보안 메커니즘 심층 이해</li><li><a href="./remote-gateway/">원격 Gateway 및 Tailscale</a> - 안전한 원격 액세스</li></ol><h2 id="하위-페이지-탐색" tabindex="-1">하위 페이지 탐색 <a class="header-anchor" href="#하위-페이지-탐색" aria-label="Permalink to &quot;하위 페이지 탐색&quot;">​</a></h2><h3 id="핵심-구성" tabindex="-1">핵심 구성 <a class="header-anchor" href="#핵심-구성" aria-label="Permalink to &quot;핵심 구성&quot;">​</a></h3><table tabindex="0"><thead><tr><th>주제</th><th>설명</th><th>예상 시간</th></tr></thead><tbody><tr><td><a href="./models-auth/">AI 모델 및 인증 구성</a></td><td>Anthropic, OpenAI, OpenRouter, Ollama 등 다양한 AI 모델 공급자 및 인증 방식 구성</td><td>15분</td></tr><tr><td><a href="./session-management/">세션 관리 및 다중 Agent</a></td><td>세션 모델, 세션 격리, 하위 Agent 협업, 컨텍스트 압축 등 핵심 개념 학습</td><td>20분</td></tr></tbody></table><h3 id="도구-시스템" tabindex="-1">도구 시스템 <a class="header-anchor" href="#도구-시스템" aria-label="Permalink to &quot;도구 시스템&quot;">​</a></h3><table tabindex="0"><thead><tr><th>주제</th><th>설명</th><th>예상 시간</th></tr></thead><tbody><tr><td><a href="./tools-browser/">브라우저 자동화 도구</a></td><td>브라우저 도구를 사용하여 웹페이지 자동화, 스크린샷, 양식 작업 등 수행</td><td>25분</td></tr><tr><td><a href="./tools-exec/">명령 실행 도구 및 승인</a></td><td>exec 도구 구성 및 사용, 보안 승인 메커니즘 및 권한 제어 이해</td><td>15분</td></tr><tr><td><a href="./tools-web/">웹 검색 및 스크래핑 도구</a></td><td>web_search 및 web_fetch 도구를 사용하여 웹 검색 및 콘텐츠 스크래핑 수행</td><td>20분</td></tr></tbody></table><h3 id="상호작용-경험" tabindex="-1">상호작용 경험 <a class="header-anchor" href="#상호작용-경험" aria-label="Permalink to &quot;상호작용 경험&quot;">​</a></h3><table tabindex="0"><thead><tr><th>주제</th><th>설명</th><th>예상 시간</th></tr></thead><tbody><tr><td><a href="./canvas/">Canvas 시각화 인터페이스 및 A2UI</a></td><td>Canvas A2UI 푸시 메커니즘, 시각화 인터페이스 작업 및 사용자 정의 인터페이스 이해</td><td>20분</td></tr><tr><td><a href="./voice-tts/">음성 웨이크업 및 텍스트 음성 변환</a></td><td>Voice Wake, Talk Mode 및 TTS 공급자 구성, 음성 상호작용 구현</td><td>15분</td></tr></tbody></table><h3 id="지능형-확장" tabindex="-1">지능형 확장 <a class="header-anchor" href="#지능형-확장" aria-label="Permalink to &quot;지능형 확장&quot;">​</a></h3><table tabindex="0"><thead><tr><th>주제</th><th>설명</th><th>예상 시간</th></tr></thead><tbody><tr><td><a href="./memory-system/">메모리 시스템 및 벡터 검색</a></td><td>메모리 시스템(SQLite-vec, FTS5, 하이브리드 검색) 구성 및 사용</td><td>25분</td></tr><tr><td><a href="./skills-platform/">스킬 플랫폼 및 ClawdHub</a></td><td>스킬 시스템, Bundled/Managed/Workspace 스킬, ClawdHub 통합 이해</td><td>20분</td></tr></tbody></table><h3 id="자동화-및-배포" tabindex="-1">자동화 및 배포 <a class="header-anchor" href="#자동화-및-배포" aria-label="Permalink to &quot;자동화 및 배포&quot;">​</a></h3><table tabindex="0"><thead><tr><th>주제</th><th>설명</th><th>예상 시간</th></tr></thead><tbody><tr><td><a href="./cron-automation/">Cron 예약 작업 및 Webhook</a></td><td>예약 작업, Webhook 트리거, Gmail Pub/Sub 등 자동화 기능 구성</td><td>20분</td></tr><tr><td><a href="./remote-gateway/">원격 Gateway 및 Tailscale</a></td><td>Tailscale Serve/Funnel 또는 SSH 터널을 통해 원격 Gateway 액세스</td><td>15분</td></tr></tbody></table><h3 id="보안-메커니즘" tabindex="-1">보안 메커니즘 <a class="header-anchor" href="#보안-메커니즘" aria-label="Permalink to &quot;보안 메커니즘&quot;">​</a></h3><table tabindex="0"><thead><tr><th>주제</th><th>설명</th><th>예상 시간</th></tr></thead><tbody><tr><td><a href="./security-sandbox/">보안 및 샌드박스 격리</a></td><td>보안 모델, 도구 권한 제어, 샌드박스 격리, Docker화 배포 이해</td><td>20분</td></tr></tbody></table><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><p>이 장의 학습을 완료한 후 다음을 수행할 수 있습니다:</p><ol><li><strong>심층 학습</strong> - <a href="./../../faq/troubleshooting/">문제 해결</a>을 확인하여 발생한 문제 해결</li><li><strong>배포 이해</strong> - <a href="./../../appendix/deployment/">배포 옵션</a>을 확인하여 Clawdbot을 프로덕션 환경에 배포</li><li><strong>확장 개발</strong> - <a href="./../../appendix/development/">개발 가이드</a>를 확인하여 플러그인 개발 및 코드 기여 방법 학습</li><li><strong>구성 확인</strong> - <a href="./../../appendix/config-reference/">전체 구성 참조</a>를 참조하여 모든 구성 옵션 확인</li></ol><div class="tip custom-block"><p class="custom-block-title">학습 제안</p><p>실제 요구사항에 따라 학습 경로를 선택하는 것이 좋습니다. 어디서부터 시작해야 할지 확실하지 않다면 &#39;빠른 시작 경로&#39;를 따라 단계적으로 학습하고, 다른 주제는 필요할 때 심층적으로 학습할 수 있습니다.</p></div>',33)])])}const u=a(d,[["render",l]]);export{f as __pageData,u as default};
